    void testDeposit() {
        account.deposit(100.0);
        account.deposit(50.0);
        assertEquals(150.0, account.getBalance());
    }

    @Test @DisplayName("Withdraw decreases balance")
    void testWithdraw() {
        account.deposit(200.0);
        account.withdraw(75.0);
        assertEquals(125.0, account.getBalance());
    }

    @Test @DisplayName("Overdraft throws IllegalStateException")
    void testOverdraft() {
        account.deposit(50.0);
        assertThrows(IllegalStateException.class, () -> account.withdraw(100.0));
        assertEquals(50.0, account.getBalance()); // balance unchanged
    }

    @Test @DisplayName("Negative deposit throws IllegalArgumentException")
    void testNegativeDeposit() {
        assertThrows(IllegalArgumentException.class, () -> account.deposit(-10.0));
    }
