import java.util.*;

public class Q4 {

    interface EmailService { void sendEmail(String to); }
    interface SmsService   { void sendSms(String to); }

    static class CallTracker {
        private final Map<String, Integer> calls = new HashMap<>();
        private boolean allPassed = true;

        void record(String methodName) {
            calls.merge(methodName, 1, Integer::sum);
        }

        int count(String methodName) {
            return calls.getOrDefault(methodName, 0);
        }

        void verify(String methodName, int expectedCount) {
            int actual = count(methodName);
            if (actual != expectedCount) {
                allPassed = false;
                System.out.println("FAIL: " + methodName + " expected " + expectedCount + " but was " + actual);
            }
        }

        boolean isAllPassed() { return allPassed; }
    }

    static class OrderService {
        private final EmailService email;
        private final SmsService sms;
        private final CallTracker emailTracker;
        private final CallTracker smsTracker;

        OrderService(EmailService email, SmsService sms, CallTracker emailTracker, CallTracker smsTracker) {
            this.email = email;
            this.sms = sms;
            this.emailTracker = emailTracker;
            this.smsTracker = smsTracker;
        }

        void placeOrder(String item) {
            email.sendEmail(item);
            emailTracker.record("sendEmail");
            // SMS not called intentionally
        }
    }

    public static void main(String[] args) {
        CallTracker emailTracker = new CallTracker();
        CallTracker smsTracker   = new CallTracker();

        EmailService emailSvc = to -> {};
        SmsService   smsSvc   = to -> {};

        OrderService service = new OrderService(emailSvc, smsSvc, emailTracker, smsTracker);
        service.placeOrder("Laptop");
        service.placeOrder("Laptop");

        System.out.println("sendEmail called: " + emailTracker.count("sendEmail"));
        System.out.println("sendSms called: "   + smsTracker.count("sendSms"));

        emailTracker.verify("sendEmail", 2);
        smsTracker.verify("sendSms", 0);

        if (emailTracker.isAllPassed() && smsTracker.isAllPassed()) {
            System.out.println("All verifications passed");
        }
    }
}

