import java.util.function.BiFunction;

public class Q6 {

    static String fizzBuzz(int n) {
        if (n % 15 == 0) return "FizzBuzz";
        if (n % 3  == 0) return "Fizz";
        if (n % 5  == 0) return "Buzz";
        return String.valueOf(n);
    }

    static int runParameterized(Object[][] cases, BiFunction<Object, Object, Boolean> checker) {
        int passed = 0;
        for (int i = 0; i < cases.length; i++) {
            Object input    = cases[i][0];
            Object expected = cases[i][1];
            Object actual   = fizzBuzz((Integer) input);
            boolean ok      = checker.apply(actual, expected);
            System.out.printf("Case %d [n=%s → '%s']: %s%n",
                i + 1, input, expected, ok ? "PASS" : "FAIL (got '" + actual + "')");
            if (ok) passed++;
        }
        return passed;
    }

    public static void main(String[] args) {
        Object[][] testCases = {
            {1,  "1"},
            {3,  "Fizz"},
            {5,  "Buzz"},
            {15, "FizzBuzz"},
            {30, "FizzBuzz"},
            {7,  "7"},
            {9,  "Fizz"},
            {20, "Buzz"}
        };

        int passed = runParameterized(testCases, Object::equals);
        System.out.println("All " + passed + " cases passed");
    }
}

