import java.util.*;

public class Q7 {

    interface UserRepository {
        String findById(int id);
    }

    static class InMemoryRepository implements UserRepository {
        private final Map<Integer, String> db = Map.of(99, "User#99", 1, "User#1");
        public String findById(int id) { return db.getOrDefault(id, "NOT_FOUND"); }
    }

    static class UserService {
        private final UserRepository repo;
        UserService(UserRepository repo) { this.repo = repo; }
        String getUser(int id) { return repo.findById(id); }
    }

    // STUB: fixed return, no tracking
    static class StubRepository implements UserRepository {
        public String findById(int id) { return "StubUser"; }
    }

    // MOCK: tracks calls, verify interaction
    static class MockRepository implements UserRepository {
        private final Map<Integer, Integer> callLog = new HashMap<>();
        public String findById(int id) {
            callLog.merge(id, 1, Integer::sum);
            return "MockUser";
        }
        void verify(int id, int expectedTimes) {
            int actual = callLog.getOrDefault(id, 0);
            if (actual == expectedTimes) {
                System.out.println("Mock: findById(" + id + ") called " + actual + " times - verified");
            } else {
                System.out.println("FAIL: expected " + expectedTimes + " but was " + actual);
            }
        }
    }

    // SPY: wraps real impl, counts calls
    static class SpyRepository implements UserRepository {
        private final UserRepository real;
        private int callCount = 0;
        SpyRepository(UserRepository real) { this.real = real; }
        public String findById(int id) {
            callCount++;
            return real.findById(id); // delegates to real impl
        }
        int getCallCount() { return callCount; }
    }

    public static void main(String[] args) {
        // STUB demo
        UserService stubService = new UserService(new StubRepository());
        System.out.println("Stub result: " + stubService.getUser(1));
        System.out.println("Stub result: " + stubService.getUser(999));

        // MOCK demo
        MockRepository mock = new MockRepository();
        UserService mockService = new UserService(mock);
        mockService.getUser(42);
        mock.verify(42, 1);

        // SPY demo
        SpyRepository spy = new SpyRepository(new InMemoryRepository());
        UserService spyService = new UserService(spy);
        System.out.println("Spy real result: " + spyService.getUser(99));
        System.out.println("Spy call count: " + spy.getCallCount());
    }
}

