public class Q8 {

    static long runUnitTests(int count) throws InterruptedException {
        System.out.println("Running " + count + " unit tests...");
        long start = System.currentTimeMillis();
        for (int i = 0; i < count; i++) {
            // pure computation — no I/O, no sleep
            int x = i * i; // simulate trivial logic
        }
        long elapsed = System.currentTimeMillis() - start;
        System.out.println(count + " unit tests passed in " + elapsed + "ms");
        return elapsed;
    }

    static long runIntegrationTests(int count) throws InterruptedException {
        System.out.println("Running " + count + " integration tests...");
        long start = System.currentTimeMillis();
        for (int i = 0; i < count; i++) {
            Thread.sleep(50); // simulate Spring context + DB query
        }
        long elapsed = System.currentTimeMillis() - start;
        System.out.println(count + " integration tests passed in " + elapsed + "ms");
        return elapsed;
    }

    public static void main(String[] args) throws InterruptedException {
        long unitMs         = runUnitTests(100);
        long integrationMs  = runIntegrationTests(5);

        long unitPerTest    = Math.max(1, unitMs) / 100;
        long intgPerTest    = integrationMs / 5;
        long ratio          = intgPerTest / Math.max(1, unitPerTest);
        System.out.println("Unit tests are ~" + ratio + "x faster per test");
    }
}
